#!/usr/bin/env bun
/**
 * MMS Parallel Harness Runner
 *
 * Executes features in parallel using git worktrees.
 * Each worktree runs an isolated Claude session.
 *
 * Usage:
 *   bun scripts/parallel-runner.ts           # Interactive mode
 *   bun scripts/parallel-runner.ts wave 1    # Execute wave 1
 *   bun scripts/parallel-runner.ts status    # Show current status
 *   bun scripts/parallel-runner.ts cleanup   # Remove all worktrees
 */

import { spawn } from 'child_process';
import { waves, getEstimatedSpeedup, getBranchName, getWorktreePath, type ParallelWave, type ParallelGroup } from './parallel-config';

// ─────────────────────────────────────────────────────────────────────────────
// COLORS
// ─────────────────────────────────────────────────────────────────────────────

const c = {
  reset: '\x1b[0m',
  bold: '\x1b[1m',
  dim: '\x1b[2m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  magenta: '\x1b[35m',
  cyan: '\x1b[36m',
};

function print(msg: string) {
  console.log(msg);
}

function printHeader(title: string) {
  print(`\n${c.bold}${c.blue}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${c.reset}`);
  print(`${c.bold}${c.blue}  ${title}${c.reset}`);
  print(`${c.bold}${c.blue}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${c.reset}\n`);
}

function printSuccess(msg: string) {
  print(`${c.green}✓ ${msg}${c.reset}`);
}

function printError(msg: string) {
  print(`${c.red}✗ ${msg}${c.reset}`);
}

function printInfo(msg: string) {
  print(`${c.blue}ℹ ${msg}${c.reset}`);
}

function printWarning(msg: string) {
  print(`${c.yellow}⚠ ${msg}${c.reset}`);
}

// ─────────────────────────────────────────────────────────────────────────────
// MACOS NOTIFICATIONS
// ─────────────────────────────────────────────────────────────────────────────

async function notify(title: string, message: string, sound: string = 'Ping') {
  try {
    const proc = Bun.spawn([
      'osascript',
      '-e',
      `display notification "${message}" with title "${title}" sound name "${sound}"`,
    ]);
    await proc.exited;
  } catch {
    // Ignore notification errors
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// GIT WORKTREE MANAGEMENT
// ─────────────────────────────────────────────────────────────────────────────

async function runCommand(cmd: string, args: string[], cwd?: string): Promise<{ stdout: string; stderr: string; exitCode: number }> {
  const proc = Bun.spawn([cmd, ...args], {
    cwd: cwd ?? process.cwd(),
    stdout: 'pipe',
    stderr: 'pipe',
  });

  const stdout = await new Response(proc.stdout).text();
  const stderr = await new Response(proc.stderr).text();
  const exitCode = await proc.exited;

  return { stdout, stderr, exitCode };
}

async function createWorktree(featureId: string): Promise<boolean> {
  const branchName = getBranchName(featureId);
  const worktreePath = getWorktreePath(featureId);

  printInfo(`Creating worktree for ${featureId}...`);

/**
 * Parallel Harness Configuration
 *
 * Defines parallel execution groups (waves) for features.
 * Uses git worktrees to enable concurrent development without conflicts.
 *
 * Architecture:
 * - Main branch: main
 * - Feature branches: feat/<feature-id>
 * - Worktrees: .trees/<feature-id>/
 *
 * Each wave can run in parallel. Features within a wave that modify
 * the same files run sequentially within that wave.
 */

export interface ParallelFeature {
  id: string;
  description: string;
  priority: number;
  filesModified: string[];
  estimatedComplexity: 'low' | 'medium' | 'high';
}

export interface ParallelGroup {
  id: string;
  name: string;
  features: ParallelFeature[];
  sequential: boolean; // If true, features run sequentially in this group
  conflictRisk: 'low' | 'medium' | 'high';
}

export interface ParallelWave {
  wave: number;
  description: string;
  groups: ParallelGroup[];
  maxConcurrency: number;
  dependsOn: number | null; // Previous wave number that must complete
}

/**
 * Wave Configuration
 *
 * Based on file conflict analysis:
 * - InfiniteCanvas.tsx: HIGH conflict (event handlers)
 * - App.tsx: MEDIUM conflict (JSX layout)
 * - MicroLayer.tsx: LOW conflict (isolated rendering)
 */
export const waves: ParallelWave[] = [
  {
    wave: 1,
    description: 'Initial parallel execution - isolated features + grouped modifications',
    dependsOn: null,
    maxConcurrency: 3,
    groups: [
      {
        id: 'group-A',
        name: 'Dependency Lines (Isolated)',
        sequential: false,
        conflictRisk: 'low',
        features: [
          {
            id: 'F023',
            description: 'Dependency lines between tasks',
            priority: 4,
            filesModified: ['apps/canvas/src/canvas/layers/MicroLayer.tsx'],
            estimatedComplexity: 'medium',
          },
        ],
      },
      {
        id: 'group-B',
        name: 'Minimap System (App.tsx)',
        sequential: true, // F025 and F123 modify same area
        conflictRisk: 'medium',
        features: [
          {
            id: 'F123',
            description: 'Minimap navigation (bird\'s eye view)',
            priority: 3,
            filesModified: ['apps/canvas/src/App.tsx', 'apps/canvas/src/components/Minimap.tsx'],

